#include <stdio.h>
#include <string.h>
#define MAX_NAME 105
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int i = 0; i < T; ++i) {
        char name[MAX_NAME];
        if (!fgets(name, sizeof(name), stdin)) break;
        size_t len = strlen(name);
        if (len && name[len-1] == '\n') name[len-1] = '\0'; // remove trailing newline
        int marks;
        if (scanf("%d", &marks) != 1) break;
        getchar(); // consume newline after marks
        if (marks > 40) printf("Pass\n");
        else printf("Fail\n");
    }
    return 0;
}

