    void check_pass() const {
        if (marks > 40) cout << "Pass" << '\n';
        else cout << "Fail" << '\n';
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    string dummy; getline(cin, dummy); // consume endline after T
    for (int i = 0; i < T; ++i) {
        string name;
        getline(cin, name);
        int marks;
        cin >> marks;
        getline(cin, dummy); // consume endline after marks
        Student s(name, marks);
        s.check_pass();
    }
    return 0;
}

code.Java:
import java.io.*;
class Student {
    String name;
    int marks;
    Student(String name, int marks) {
        this.name = name;
        this.marks = marks;
    }
    void checkPass(PrintWriter out) {
        if (marks > 40) out.println("Pass");
        else out.println("Fail");
    }
}
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter out = new PrintWriter(new BufferedWriter(new OutputStreamWriter(System.out)));
        int T = Integer.parseInt(br.readLine().trim());
        for (int i = 0; i < T; ++i) {
            String name = br.readLine();
            int marks = Integer.parseInt(br.readLine().trim());
            Student s = new Student(name, marks);
            s.checkPass(out);
        }
        out.flush();
    }
}

